import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for proj in data.get('projects', []):
        proj_name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = {'requested': pkg.get('requestedVersion',''), 'resolved': pkg.get('resolvedVersion','')}
        result[proj_name] = pkgs
    return result

b = extract_packages(baseline)
a = extract_packages(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, {}).get('resolved', 'N/A')
        av = ap.get(pkg, {}).get('resolved', 'N/A')
        br = bp.get(pkg, {}).get('requested', '')
        ar = ap.get(pkg, {}).get('requested', '')
        if bv != av or br != ar:
            changes = True
            print(f'  {proj}: {pkg} requested {br}->{ar}, resolved {bv}->{av}')

if not changes:
    print('  None')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(bp.keys()):
        bv = bp.get(pkg, {}).get('resolved', '')
        av = ap.get(pkg, {}).get('resolved', '')
        if bv == av:
            print(f'  {proj}: {pkg} = {bv}')
"

